<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Ubuntu Desktop</title>
<style>
* { box-sizing: border-box; margin: 0; padding: 0; }
html, body {
  width: 100%; height: 100%; overflow: hidden;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  user-select: none;
}

#desktop {
  position: relative;
  width: 100vw;
  height: 100vh;
  background:
    radial-gradient(ellipse at 25% 20%, rgba(94, 39, 80, 0.7) 0%, transparent 50%),
    radial-gradient(ellipse at 75% 80%, rgba(42, 74, 124, 0.7) 0%, transparent 50%),
    linear-gradient(135deg, #2c001e 0%, #1a1a2e 100%);
  overflow: hidden;
}

#topbar {
  position: absolute;
  top: 0; left: 0; right: 0;
  height: 28px;
  background: rgba(20, 20, 20, 0.92);
  display: flex;
  align-items: center;
  padding: 0 12px;
  color: #fff;
  font-size: 13px;
  z-index: 1000;
  border-bottom: 1px solid rgba(255,255,255,0.08);
}

#topbar .menu { display: flex; gap: 4px; margin-right: 20px; }
#topbar .menu-item {
  padding: 4px 10px;
  border-radius: 4px;
  cursor: pointer;
  transition: background 0.15s;
}
#topbar .menu-item:hover { background: rgba(255,255,255,0.1); }
#topbar .menu-item.active { background: rgba(233, 84, 32, 0.25); }
#topbar .spacer { flex: 1; }
#topbar .tray { display: flex; gap: 14px; align-items: center; font-size: 12px; }
#topbar .tray-item {
  cursor: pointer;
  padding: 2px 6px;
  border-radius: 3px;
}
#topbar .tray-item:hover { background: rgba(255,255,255,0.1); }

#taskbar {
  position: absolute;
  bottom: 16px;
  left: 50%;
  transform: translateX(-50%);
  background: rgba(30, 30, 30, 0.75);
  backdrop-filter: blur(20px);
  border: 1px solid rgba(255,255,255,0.12);
  border-radius: 18px;
  padding: 8px 12px;
  display: flex;
  gap: 10px;
  z-index: 1000;
  box-shadow: 0 10px 40px rgba(0,0,0,0.5);
}

.launcher {
  width: 48px;
  height: 48px;
  border-radius: 12px;
  background: linear-gradient(135deg, #3a3a3a, #1a1a1a);
  border: 1px solid rgba(255,255,255,0.08);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 22px;
  color: #fff;
  transition: all 0.2s;
  position: relative;
}
.launcher:hover {
  transform: translateY(-4px) scale(1.05);
  background: linear-gradient(135deg, #4a4a4a, #2a2a2a);
  box-shadow: 0 6px 20px rgba(233, 84, 32, 0.3);
}
.launcher.active::after {
  content: '';
  position: absolute;
  bottom: -8px;
  left: 50%;
  transform: translateX(-50%);
  width: 4px;
  height: 4px;
  background: #e95420;
  border-radius: 50%;
}

.window {
  position: absolute;
  min-width: 360px;
  min-height: 240px;
  background: #1e1e1e;
  border: 1px solid rgba(255,255,255,0.1);
  border-radius: 10px;
  box-shadow: 0 20px 60px rgba(0,0,0,0.6);
  overflow: hidden;
  display: flex;
  flex-direction: column;
  color: #fff;
}

.window-titlebar {
  height: 36px;
  background: linear-gradient(180deg, #2d2d2d, #1f1f1f);
  display: flex;
  align-items: center;
  padding: 0 12px;
  cursor: move;
  border-bottom: 1px solid rgba(255,255,255,0.05);
}
.window-title {
  flex: 1;
  font-size: 13px;
  font-weight: 500;
  color: #ddd;
}
.window-controls { display: flex; gap: 8px; }
.window-controls button {
  width: 14px;
  height: 14px;
  border-radius: 50%;
  border: none;
  cursor: pointer;
  font-size: 0;
  transition: filter 0.15s;
}
.window-controls button:hover { filter: brightness(1.3); }
.win-minimize { background: #ffbd2e; }
.win-maximize { background: #28c941; }
.win-close { background: #ff5f57; }

.window-body {
  flex: 1;
  overflow: auto;
  background: #1e1e1e;
  display: flex;
  flex-direction: column;
}

#files-toolbar {
  display: flex;
  align-items: center;
  padding: 8px 12px;
  background: #252525;
  border-bottom: 1px solid rgba(255,255,255,0.05);
  gap: 8px;
}
#files-up {
  background: #333;
  border: 1px solid rgba(255,255,255,0.1);
  color: #fff;
  padding: 5px 12px;
  border-radius: 5px;
  cursor: pointer;
  font-size: 12px;
  transition: background 0.15s;
}
#files-up:hover { background: #444; }
#files-up:active { background: #555; }

#files-path {
  flex: 1;
  background: #1a1a1a;
  border: 1px solid rgba(255,255,255,0.1);
  color: #fff;
  padding: 5px 10px;
  border-radius: 5px;
  font-family: 'SF Mono', Consolas, monospace;
  font-size: 12px;
  outline: none;
}

#files-list {
  flex: 1;
  padding: 8px;
  overflow-y: auto;
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.fs-item {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 6px 10px;
  border-radius: 5px;
  cursor: pointer;
  font-size: 13px;
  transition: background 0.1s;
}
.fs-item:hover { background: rgba(233, 84, 32, 0.2); }
.fs-item.selected { background: rgba(233, 84, 32, 0.35); }
.fs-icon { font-size: 16px; width: 20px; text-align: center; }

#tabs {
  display: flex;
  background: #252525;
  border-bottom: 1px solid rgba(255,255,255,0.05);
  overflow-x: auto;
  min-height: 34px;
  align-items: stretch;
}

.tab {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 0 12px;
  background: #2a2a2a;
  border-right: 1px solid rgba(255,255,255,0.05);
  cursor: pointer;
  font-size: 12px;
  color: #aaa;
  white-space: nowrap;
  transition: background 0.1s;
  min-width: 120px;
  max-width: 200px;
}
.tab:hover { background: #333; color: #ccc; }
.tab.active {
  background: #1e1e1e;
  color: #fff;
  box-shadow: inset 0 -2px 0 #e95420;
}
.tab-name {
  flex: 1;
  overflow: hidden;
  text-overflow: ellipsis;
}
.tab-close {
  width: 16px;
  height: 16px;
  border-radius: 50%;
  background: rgba(255,255,255,0.08);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 10px;
  color: #aaa;
  flex-shrink: 0;
}
.tab-close:hover { background: #ff5f57; color: #fff; }

#new-tab {
  background: transparent;
  border: none;
  color: #aaa;
  padding: 0 14px;
  cursor: pointer;
  font-size: 16px;
  border-right: 1px solid rgba(255,255,255,0.05);
  transition: background 0.1s;
}
#new-tab:hover { background: #333; color: #fff; }

#editor {
  flex: 1;
  background: #1e1e1e;
  color: #fff;
  border: none;
  padding: 12px;
  font-family: 'SF Mono', Consolas, monospace;
  font-size: 13px;
  resize: none;
  outline: none;
  line-height: 1.6;
  user-select: text;
}

.hidden { display: none !important; }

::-webkit-scrollbar { width: 8px; height: 8px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.15); border-radius: 4px; }
::-webkit-scrollbar-thumb:hover { background: rgba(255,255,255,0.25); }
</style>
</head>
<body>
<div id="desktop">
  <div id="topbar">
    <div class="menu">
      <div class="menu-item active">Activities</div>
      <div class="menu-item">Files</div>
      <div class="menu-item">Terminal</div>
      <div class="menu-item">Help</div>
    </div>
    <div class="spacer"></div>
    <div class="tray">
      <div class="tray-item">🔊</div>
      <div class="tray-item">📶</div>
      <div class="tray-item">🔋 85%</div>
      <div class="tray-item" id="clock">--:--</div>
    </div>
  </div>

  <div id="taskbar">
    <button class="launcher" id="open-files" title="Files">📁</button>
    <button class="launcher" id="open-notepad" title="Notepad">📝</button>
  </div>

  <div class="window hidden" id="files-window" style="left: 80px; top: 60px; width: 640px; height: 420px;">
    <div class="window-titlebar">
      <div class="window-title">Files</div>
      <div class="window-controls">
        <button class="win-minimize" title="Minimize">_</button>
        <button class="win-maximize" title="Maximize">□</button>
        <button class="win-close" title="Close">×</button>
      </div>
    </div>
    <div class="window-body">
      <div id="files-toolbar">
        <button id="files-up">↑ Up</button>
        <input id="files-path" type="text" readonly value="/">
      </div>
      <div id="files-list"></div>
    </div>
  </div>

  <div class="window hidden" id="notepad-window" style="left: 180px; top: 100px; width: 520px; height: 380px;">
    <div class="window-titlebar">
      <div class="window-title">Notepad</div>
      <div class="window-controls">
        <button class="win-minimize" title="Minimize">_</button>
        <button class="win-maximize" title="Maximize">□</button>
        <button class="win-close" title="Close">×</button>
      </div>
    </div>
    <div class="window-body">
      <div id="tabs">
        <button id="new-tab">+</button>
      </div>
      <textarea id="editor" placeholder="Start typing..."></textarea>
    </div>
  </div>
</div>

<script>
const filesystem = {
  '/': ['bin', 'etc', 'home', 'usr', 'var'],
  '/bin': ['bash', 'cat', 'ls', 'cp', 'mv', 'rm', 'mkdir', 'chmod', 'chown'],
  '/etc': ['hostname', 'hosts', 'passwd', 'fstab', 'profile', 'resolv.conf'],
  '/home': ['user'],
  '/home/user': ['Documents', 'Downloads', 'Pictures', '.bashrc', '.profile', 'readme.txt'],
  '/home/user/Documents': ['notes.txt', 'todo.md', 'project.md', 'ideas.md'],
  '/home/user/Downloads': ['installer.deb', 'archive.zip', 'photo.jpg'],
  '/home/user/Pictures': ['wallpaper.png', 'screenshot.png', 'vacation.jpg', 'avatar.png'],
  '/usr': ['bin', 'lib', 'share', 'include'],
  '/usr/bin': ['python3', 'node', 'git', 'curl', 'wget'],
  '/usr/lib': ['libc.so', 'libm.so', 'libpthread.so'],
  '/usr/share': ['fonts', 'icons', 'locale'],
  '/usr/include': ['stdio.h', 'stdlib.h'],
  '/var': ['log', 'tmp', 'cache', 'lib'],
  '/var/log': ['syslog', 'auth.log', 'kern.log', 'dpkg.log'],
  '/var/tmp': [],
  '/var/cache': ['apt', 'man'],
  '/var/lib': ['dpkg', 'apt']
};

let currentPath = '/';

function renderFiles() {
  document.getElementById('files-path').value = currentPath;
  const list = document.getElementById('files-list');
  list.innerHTML = '';

  const items = filesystem[currentPath] || [];
  if (items.length === 0) {
    list.innerHTML = '<div style="padding: 20px; color: #666; text-align: center; font-size: 13px;">This folder is empty</div>';
    return;
  }

  items.forEach(name => {
    const div = document.createElement('div');
    div.className = 'fs-item';
    const isFolder = filesystem[currentPath + '/' + name] !== undefined;
    div.innerHTML = '<span class="fs-icon">' + (isFolder ? '📁' : '📄') + '</span><span>' + name + '</span>';

    div.addEventListener('click', () => {
      document.querySelectorAll('.fs-item').forEach(el => el.classList.remove('selected'));
      div.classList.add('selected');
    });

    div.addEventListener('dblclick', () => {
      if (isFolder) {
        currentPath = currentPath === '/' ? '/' + name : currentPath + '/' + name;
        renderFiles();
      }
    });

    list.appendChild(div);
  });
}

document.getElementById('files-up').addEventListener('click', () => {
  if (currentPath === '/') return;
  const parts = currentPath.split('/').filter(Boolean);
  parts.pop();
  currentPath = parts.length === 0 ? '/' : '/' + parts.join('/');
  renderFiles();
});

let tabs = [];
let activeTabId = null;

function loadTabs() {
  const saved = localStorage.getItem('notepad-tabs');
  if (saved) {
    try {
      const data = JSON.parse(saved);
      if (data.tabs && Array.isArray(data.tabs) && data.tabs.length > 0) {
        tabs = data.tabs;
        activeTabId = data.activeTabId;
        if (!tabs.find(t => t.id === activeTabId)) {
          activeTabId = tabs[0].id;
        }
        return;
      }
    } catch(e) {}
  }
  const id = Date.now();
  tabs.push({ id, name: 'Untitled', content: '' });
  activeTabId = id;
}

function saveTabs() {
  localStorage.setItem('notepad-tabs', JSON.stringify({ tabs, activeTabId }));
}

function renderTabs() {
  const tabsEl = document.getElementById('tabs');
  const newTabBtn = document.getElementById('new-tab');
  tabsEl.innerHTML = '';
  tabsEl.appendChild(newTabBtn);

  tabs.forEach(tab => {
    const tabEl = document.createElement('div');
    tabEl.className = 'tab' + (tab.id === activeTabId ? ' active' : '');
    tabEl.innerHTML = '<span class="tab-name">' + tab.name + '</span><span class="tab-close">×</span>';

    tabEl.addEventListener('click', (e) => {
      if (e.target.classList.contains('tab-close')) {
        e.stopPropagation();
        tabs = tabs.filter(t => t.id !== tab.id);
        if (tabs.length === 0) {
          const id = Date.now();
          tabs.push({ id, name: 'Untitled', content: '' });
          activeTabId = id;
        } else if (activeTabId === tab.id) {
          activeTabId = tabs[0].id;
        }
        saveTabs();
        renderTabs();
        renderEditor();
      } else {
        activeTabId = tab.id;
        saveTabs();
        renderTabs();
        renderEditor();
      }
    });

    tabsEl.appendChild(tabEl);
  });
}

function renderEditor() {
  const editor = document.getElementById('editor');
  const tab = tabs.find(t => t.id === activeTabId);
  editor.value = tab ? tab.content : '';
}

document.getElementById('new-tab').addEventListener('click', () => {
  const id = Date.now();
  tabs.push({ id, name: 'Untitled ' + (tabs.length + 1), content: '' });
  activeTabId = id;
  saveTabs();
  renderTabs();
  renderEditor();
  document.getElementById('editor').focus();
});

document.getElementById('editor').addEventListener('input', (e) => {
  const tab = tabs.find(t => t.id === activeTabId);
  if (tab) {
    tab.content = e.target.value;
    saveTabs();
  }
});

function makeDraggable(windowEl) {
  const titlebar = windowEl.querySelector('.window-titlebar');
  let isDragging = false;
  let startX, startY, startLeft, startTop;

  titlebar.addEventListener('mousedown', (e) => {
    if (e.target.tagName === 'BUTTON') return;
    isDragging = true;
    startX = e.clientX;
    startY = e.clientY;
    const rect = windowEl.getBoundingClientRect();
    startLeft = rect.left;
    startTop = rect.top;
    document.body.style.userSelect = 'none';
  });

  document.addEventListener('mousemove', (e) => {
    if (!isDragging) return;
    const dx = e.clientX - startX;
    const dy = e.clientY - startY;
    windowEl.style.left = Math.max(0, startLeft + dx) + 'px';
    windowEl.style.top = Math.max(28, startTop + dy) + 'px';
  });

  document.addEventListener('mouseup', () => {
    isDragging = false;
    document.body.style.userSelect = '';
  });
}

let highestZ = 100;
document.querySelectorAll('.window').forEach(win => {
  makeDraggable(win);
  win.querySelector('.win-close').addEventListener('click', () => {
    win.classList.add('hidden');
  });
  win.addEventListener('mousedown', () => {
    highestZ++;
    win.style.zIndex = highestZ;
  });
});

document.getElementById('open-files').addEventListener('click', () => {
  const win = document.getElementById('files-window');
  win.classList.remove('hidden');
  highestZ++;
  win.style.zIndex = highestZ;
  renderFiles();
});

document.getElementById('open-notepad').addEventListener('click', () => {
  const win = document.getElementById('notepad-window');
  win.classList.remove('hidden');
  highestZ++;
  win.style.zIndex = highestZ;
  renderTabs();
  renderEditor();
});

function updateClock() {
  const now = new Date();
  const h = String(now.getHours()).padStart(2, '0');
  const m = String(now.getMinutes()).padStart(2, '0');
  document.getElementById('clock').textContent = h + ':' + m;
}
updateClock();
setInterval(updateClock, 30000);

loadTabs();
renderTabs();
renderEditor();
renderFiles();
</script>
</body>
</html>
